  /// Close consumer
  fn handle_close_consumer(&self, req: TCloseConsumerReq) -> thrift::Result<common::TSStatus>;
  /// Create subscription
  fn handle_create_subscription(&self, req: TSubscribeReq) -> thrift::Result<common::TSStatus>;
  /// Close subscription by consumer
  fn handle_drop_subscription(&self, req: TUnsubscribeReq) -> thrift::Result<common::TSStatus>;
  /// Close subscription by session
  fn handle_drop_subscription_by_id(&self, req: TDropSubscriptionReq) -> thrift::Result<common::TSStatus>;
  /// Show Subscription on topic name, if name is empty, show all subscriptions
  fn handle_show_subscription(&self, req: TShowSubscriptionReq) -> thrift::Result<TShowSubscriptionResp>;
  /// Get all subscription information. It is used for DataNode registration and restart
  fn handle_get_all_subscription_info(&self) -> thrift::Result<TGetAllSubscriptionInfoResp>;
