  fn handle_get_time_slot_list(&self, req: TGetTimeSlotListReq) -> thrift::Result<TGetTimeSlotListResp>;
  fn handle_count_time_slot_list(&self, req: TCountTimeSlotListReq) -> thrift::Result<TCountTimeSlotListResp>;
  /// Get the given database's assigned SeriesSlots
  fn handle_get_series_slot_list(&self, req: TGetSeriesSlotListReq) -> thrift::Result<TGetSeriesSlotListResp>;
  /// Create a CQ
  /// 
  /// @return SUCCESS_STATUS if the cq was created successfully
  fn handle_create_c_q(&self, req: TCreateCQReq) -> thrift::Result<common::TSStatus>;
  /// Drop a CQ
  /// 
  /// @return SUCCESS_STATUS if the CQ was removed successfully
  fn handle_drop_c_q(&self, req: TDropCQReq) -> thrift::Result<common::TSStatus>;
  /// Return the cq table of config leader
  fn handle_show_c_q(&self) -> thrift::Result<TShowCQResp>;
